import React, { useEffect, useState } from "react";
import api from "../api";

export default function AdminKycPanel({ username, onLogout }) {
  const [kycList, setKycList] = useState([]);
  const [info, setInfo] = useState("");

  useEffect(() => {
    loadKyc();
  }, []);

  const loadKyc = async () => {
    try {
      const res = await api.get("/admin/kyc");
      setKycList(res.data);
    } catch {
      setInfo("Error loading KYC records.");
    }
  };

  const act = async (id, action) => {
    try {
      await api.post(`/admin/kyc/${id}/${action}`);
      setInfo(`KYC ${action}d`);
      loadKyc();
    } catch {
      setInfo(`Failed to ${action} KYC`);
    }
  };

  return (
    <div className="dashboard">
      <header className="top-bar">
        <div>
          <h1>Secure Bank Admin</h1>
          <p className="subtitle">Logged in as {username}</p>
        </div>
        <button onClick={onLogout}>Logout</button>
      </header>

      <section className="panel">
        <h2>Pending KYC Approvals</h2>
        <table>
          <thead>
            <tr>
              <th>User ID</th>
              <th>Aadhaar</th>
              <th>PAN</th>
              <th>Address</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {kycList.map((k) => (
              <tr key={k.id}>
                <td>{k.user?.id}</td>
                <td>{k.aadhaarNumber}</td>
                <td>{k.panNumber}</td>
                <td>{k.address}</td>
                <td>{k.status}</td>
                <td>
                  <button onClick={() => act(k.id, "approve")}>Approve</button>
                  <button onClick={() => act(k.id, "reject")}>Reject</button>
                </td>
              </tr>
            ))}
            {kycList.length === 0 && (
              <tr>
                <td colSpan="6" style={{ textAlign: "center" }}>
                  No KYC records.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </section>

      {info && <p className="info">{info}</p>}
    </div>
  );
}
